// Parse AI config and store in workflow_context
let text = input;
if (typeof text === 'object') text = text.text || text.content || JSON.stringify(text);
text = String(text);

try {
  text = text.replace(/<think[^>]*>[\s\S]*?<\/think>/gi, '').trim();
  text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '');
  let start = text.indexOf('{');
  let end = text.lastIndexOf('}');
  if (start >= 0 && end > start) text = text.substring(start, end + 1);

  let config = JSON.parse(text);

  workflow_context['theme'] = config.theme || 'a music video';
  workflow_context['genre'] = config.genre || 'pop, cinematic';
  workflow_context['visualStyle'] = config.visualStyle || 'cinematic, vibrant';
  workflow_context['numCharacters'] = config.numCharacters || 2;
  workflow_context['characterIdeas'] = config.characterIdeas || [];

  console.log('[parse-config] Theme:', workflow_context['theme']);
  console.log('[parse-config] Genre:', workflow_context['genre']);
  console.log('[parse-config] Style:', workflow_context['visualStyle']);
  console.log('[parse-config] Characters:', workflow_context['numCharacters']);

  return config;
} catch (e) {
  console.log('[parse-config] Parse error, using defaults:', e.message);
  workflow_context['theme'] = 'a music video';
  workflow_context['genre'] = 'pop, cinematic';
  workflow_context['visualStyle'] = 'cinematic, vibrant colors';
  workflow_context['numCharacters'] = 2;
  workflow_context['characterIdeas'] = [];
  return { theme: workflow_context['theme'], genre: workflow_context['genre'] };
}

// Store lyrics for later use
let lyrics = input;
if (typeof lyrics === 'object') {
  lyrics = lyrics.text || lyrics.content || JSON.stringify(lyrics);
}
lyrics = String(lyrics || '');
console.log('[store-lyrics] Lyrics:', lyrics.substring(0, 200));
workflow_context['lyrics'] = lyrics;
return lyrics;

// Store music path from music_gen output
let path = input;
console.log('[store-music-path] Music path:', path);
workflow_context['musicPath'] = path;
return path;

// Process STT segments and create scene data with VARIABLE durations (up to 10s)
// Scenes sync with natural speech/lyric boundaries
// FIXED: Properly subdivide long gaps into multiple scenes
let sttResult = input;
let duration = parseFloat(input2) || 60;

console.log('[process-segments] STT result type:', typeof sttResult);
console.log('[process-segments] Duration:', duration);

let segments = [];
let fullText = '';

if (sttResult) {
  if (typeof sttResult === 'object') {
    segments = sttResult.segments || sttResult || [];
    fullText = sttResult.text || '';
  } else if (Array.isArray(sttResult)) {
    segments = sttResult;
  } else {
    fullText = String(sttResult);
  }
}

console.log('[process-segments] Got', segments.length, 'STT segments');

// Config: min/max scene duration
let minSceneDuration = 3;
let maxSceneDuration = 10;
let pauseThreshold = 0.8; // seconds of silence to trigger scene break

let scenes = [];

// Get lyrics for fallback text
let lyrics = workflow_context['lyrics'] || fullText || '';
lyrics = String(lyrics);
let rawParts = lyrics.split(/\[(verse|chorus|bridge|outro)\]/i);
let lyricParts = [];
for (let i = 0; i < rawParts.length; i++) {
  let p = rawParts[i];
  if (p && typeof p === 'string') {
    let trimmed = p.trim();
    let isLabel = (trimmed === 'verse' || trimmed === 'chorus' || trimmed === 'bridge' || trimmed === 'outro');
    if (trimmed && !isLabel) {
      lyricParts.push(trimmed);
    }
  }
}
if (lyricParts.length === 0) lyricParts = ['Music plays...'];

// Helper: add filler scenes to cover a gap period
function addFillerScenes(fromTime, toTime, scenesArray) {
  let gapDur = toTime - fromTime;
  if (gapDur <= 0) return fromTime;
  let numScenes = Math.ceil(gapDur / maxSceneDuration);
  let sceneDur = gapDur / numScenes;
  for (let j = 0; j < numScenes; j++) {
    let sStart = fromTime + (j * sceneDur);
    let sEnd = Math.min(fromTime + ((j + 1) * sceneDur), toTime);
    let partIdx = Math.floor(scenesArray.length * lyricParts.length / Math.max(1, (scenesArray.length + numScenes)));
    scenesArray.push({
      text: lyricParts[partIdx % lyricParts.length] || 'Music continues...',
      start: sStart,
      end: sEnd,
      duration: sEnd - sStart
    });
  }
  return toTime;
}

if (Array.isArray(segments) && segments.length > 0) {
  // Sort segments by start time
  segments.sort((a, b) => (a.start || 0) - (b.start || 0));

  let currentScene = { text: '', start: 0, segments: [] };
  let timeTracker = 0; // Track where we are in the timeline

  for (let i = 0; i < segments.length; i++) {
    let seg = segments[i];
    let segStart = seg.start || 0;
    let segEnd = seg.end || segStart + 1;
    let segText = seg.text || '';

    // If this segment starts after our tracker, there may be a gap
    if (segStart > timeTracker && currentScene.segments.length === 0) {
      // No current scene content - add filler scenes for the intro gap
      timeTracker = addFillerScenes(timeTracker, segStart, scenes);
      currentScene.start = timeTracker;
    }

    // Calculate current scene duration with this segment
    let currentDur = currentScene.segments.length > 0 
      ? (currentScene.segments[currentScene.segments.length - 1].end - currentScene.start) 
      : 0;
    let prevEnd = currentScene.segments.length > 0 
      ? currentScene.segments[currentScene.segments.length - 1].end 
      : currentScene.start;
    let gap = segStart - prevEnd;
    let potentialDur = segEnd - currentScene.start;

    // Decide if we should break
    let shouldBreak = false;

    // Break if: significant pause AND scene is at least min duration
    if (gap >= pauseThreshold && currentDur >= minSceneDuration) {
      shouldBreak = true;
    }
    // Break if: adding this segment would exceed max duration
    if (potentialDur > maxSceneDuration && currentScene.segments.length > 0) {
      shouldBreak = true;
    }

    if (shouldBreak) {
      // Finalize current scene at the last segment's end (not the gap)
      let sceneEnd = prevEnd;
      if (currentScene.text.trim()) {
        scenes.push({
          text: currentScene.text.trim(),
          start: currentScene.start,
          end: sceneEnd,
          duration: sceneEnd - currentScene.start
        });
      }
      timeTracker = sceneEnd;

      // If there's a gap before this segment, add filler scenes
      if (segStart > timeTracker) {
        timeTracker = addFillerScenes(timeTracker, segStart, scenes);
      }

      // Start new scene
      currentScene = { text: '', start: timeTracker, segments: [] };
    }

    // Add segment to current scene
    currentScene.text += ' ' + segText;
    currentScene.segments.push(seg);
    timeTracker = Math.max(timeTracker, segEnd);
  }

  // Finalize last scene with segments
  if (currentScene.segments.length > 0) {
    let lastSeg = currentScene.segments[currentScene.segments.length - 1];
    let sceneEnd = lastSeg.end || timeTracker;
    // Ensure scene doesn't exceed max duration
    if (sceneEnd - currentScene.start > maxSceneDuration) {
      sceneEnd = currentScene.start + maxSceneDuration;
    }
    scenes.push({
      text: currentScene.text.trim(),
      start: currentScene.start,
      end: sceneEnd,
      duration: sceneEnd - currentScene.start
    });
    timeTracker = sceneEnd;
  }

  // Add filler scenes for any remaining time (instrumental outro)
  if (duration > timeTracker + minSceneDuration) {
    addFillerScenes(timeTracker, duration, scenes);
  } else if (duration > timeTracker) {
    // Extend last scene to fill small gap
    if (scenes.length > 0) {
      let last = scenes[scenes.length - 1];
      last.end = duration;
      last.duration = last.end - last.start;
    }
  }
} else {
  // Fallback: no STT segments, create scenes from lyrics with variable duration
  let numScenes = Math.ceil(duration / maxSceneDuration);
  let sceneDur = duration / numScenes;
  for (let i = 0; i < numScenes; i++) {
    let start = i * sceneDur;
    let end = Math.min((i + 1) * sceneDur, duration);
    let partIdx = Math.floor(i * lyricParts.length / numScenes);
    scenes.push({
      text: lyricParts[partIdx] || 'Music continues...',
      start: start,
      end: end,
      duration: end - start
    });
  }
}

// Final pass: ensure all scenes are within max duration (split if needed)
let finalScenes = [];
for (let i = 0; i < scenes.length; i++) {
  let sc = scenes[i];
  if (sc.duration > maxSceneDuration) {
    // Split this scene
    let numParts = Math.ceil(sc.duration / maxSceneDuration);
    let partDur = sc.duration / numParts;
    for (let j = 0; j < numParts; j++) {
      finalScenes.push({
        text: sc.text,
        start: sc.start + (j * partDur),
        end: sc.start + ((j + 1) * partDur),
        duration: partDur
      });
    }
  } else {
    finalScenes.push(sc);
  }
}
scenes = finalScenes;

// Log scene info
let totalDur = 0;
for (let i = 0; i < scenes.length; i++) {
  console.log('[process-segments] Scene', i, ':', scenes[i].start.toFixed(1), '-', scenes[i].end.toFixed(1), 's (', scenes[i].duration.toFixed(1), 's) -', scenes[i].text.substring(0, 40));
  totalDur += scenes[i].duration;
}

console.log('[process-segments] Created', scenes.length, 'scenes, total duration:', totalDur.toFixed(1), 's (music:', duration.toFixed(1), 's)');
workflow_context['scenes'] = scenes;
workflow_context['numScenes'] = scenes.length;
workflow_context['musicDuration'] = duration;

return scenes;

data.template:
Create a music video storyboard for these lyrics:

{{lyrics}}

NUMBER OF CHARACTERS: {{numCharacters}}
VISUAL STYLE: {{style}}
NUMBER OF SCENES: {{numScenes}}

For each scene, I need:
1. DISTINCT main characters with detailed visual descriptions
2. Scene setting and mood
3. Character actions/poses

RULES:
- Create exactly {{numCharacters}} unique characters with detailed appearances
- Create exactly {{numScenes}} scenes (scenes have variable duration 3-10 seconds, synced to lyrics)
- Each scene should have 1-2 characters max
- Describe character clothing, colors, features in detail
- Make scenes visually match the lyrics mood and timing
- Keep image prompts concise but descriptive

Output JSON:
{
  "characters": [
    { "name": "Name", "description": "detailed visual description" }
  ],
  "scenes": [
    {
      "number": 1,
      "lyrics_segment": "the lyrics for this part",
      "setting": "scene location/environment",
      "mood": "emotional tone",
      "charactersPresent": ["Character Name"],
      "action": "what characters are doing",
      "image_prompt": "[FULL character descriptions], [action], [setting], {{style}}"
    }
  ]
}

