// Get number of scenes from workflow context
let numScenes = workflow_context['numScenes'] || Math.ceil((workflow_context['musicDuration'] || 60) / 10);
console.log('[get-num-scenes] Returning:', numScenes);
return String(numScenes);

// Parse storyboard JSON
console.log('[parse-storyboard] === START ===');
let text = input;
if (typeof text === 'object') {
  text = text.text || text.content || JSON.stringify(text);
}
text = String(text);

try {
  text = text.replace(/<think[^>]*>[\s\S]*?<\/think[^>]*>/gi, '');
  text = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '');

  let startIdx = text.indexOf('{');
  let endIdx = text.lastIndexOf('}');
  if (startIdx >= 0 && endIdx > startIdx) {
    text = text.substring(startIdx, endIdx + 1);
  }

  let storyboard = JSON.parse(text);

  let characters = [];
  if (storyboard.characters) {
    for (let char of storyboard.characters) {
      characters.push({ name: char.name, description: char.description });
    }
  }

  let scenePrompts = [];
  let timeSegments = workflow_context['scenes'] || [];

  if (storyboard.scenes) {
    for (let i = 0; i < storyboard.scenes.length; i++) {
      let scene = storyboard.scenes[i];
      let timeSeg = timeSegments[i] || { start: i * 10, end: (i + 1) * 10, text: '' };

      scenePrompts.push({
        number: scene.number || i + 1,
        image_prompt: scene.image_prompt || scene.imagePrompt || 'cinematic scene',
        setting: scene.setting || '',
        action: scene.action || '',
        lyrics: scene.lyrics_segment || timeSeg.text || '',
        start: timeSeg.start,
        end: timeSeg.end,
        duration: (timeSeg.end - timeSeg.start) || 10
      });
    }
  }

  workflow_context['characters'] = characters;
  workflow_context['scenePrompts'] = scenePrompts;

  console.log('[parse-storyboard] Got', characters.length, 'characters,', scenePrompts.length, 'scenes');

  return { characters: characters, scenes: scenePrompts };
} catch (e) {
  console.log('[parse-storyboard] ERROR:', e.message);
  return { characters: [{ name: 'Singer', description: 'stylish singer' }], scenes: [{ number: 1, image_prompt: 'music video scene', duration: 10 }] };
}

// Extract characters for loop
let chars = workflow_context['characters'] || [];
console.log('[extract-characters] Returning', chars.length, 'characters');
if (chars.length === 0) {
  chars = [{ name: 'Singer', description: 'a stylish young singer with flowing hair, wearing a sparkly outfit' }];
}
return chars;

let char = input;
if (typeof char === 'string') try { char = JSON.parse(char); } catch(e) {}
return char && char.name || 'Character';

let char = input;
if (typeof char === 'string') try { char = JSON.parse(char); } catch(e) {}
return char && char.description || 'a character';

// Store character image
let img = input;
console.log('[store-char-image] Storing char', loop_index);
if (!workflow_context['characterImages']) workflow_context['characterImages'] = {};
workflow_context['characterImages']['char_' + loop_index] = img;
return img;

// Extract scenes for loop (from process-segments, not storyboard)
// input = storyboard result (used for characters only)
// input2 = character images array (from character-loop-end, used as sync point)
let scenes = workflow_context['scenes'] || [];
console.log('[extract-scene-prompts] Returning', scenes.length, 'scenes from process-segments, char images ready:', !!input2);
if (scenes.length === 0) {
  // Fallback: create scenes based on duration (up to 10s each)
  let dur = workflow_context['musicDuration'] || 60;
  let numScenes = Math.ceil(dur / 10);
  let sceneDur = dur / numScenes;
  for (let i = 0; i < numScenes; i++) {
    let start = i * sceneDur;
    let end = Math.min((i + 1) * sceneDur, dur);
    scenes.push({ text: 'music playing', start: start, end: end, duration: end - start });
  }
}
return scenes;

// Get scene text (STT lyrics for this segment)
let scene = input;
if (typeof scene === 'string') try { scene = JSON.parse(scene); } catch(e) {}
let text = (scene && scene.text) || 'music playing';
text = String(text);
console.log('[get-scene-text] Scene', loop_index, ':', text.substring(0, 50));
return text;

// Get character descriptions for scene prompt
let chars = workflow_context['characters'] || [];
let charDesc = '';
for (let i = 0; i < chars.length; i++) {
  let c = chars[i];
  if (c && c.name && c.description) {
    charDesc += c.name + ': ' + c.description + '; ';
  }
}
if (!charDesc) charDesc = 'stylish singer performing';
charDesc = String(charDesc);
console.log('[get-scene-context] Characters:', charDesc.substring(0, 100));
return charDesc;

let scene = input;
if (typeof scene === 'string') try { scene = JSON.parse(scene); } catch(e) {}
scene = scene || {};
let dur = scene.duration || (scene.end - scene.start) || 10;
console.log('[get-scene-duration] Scene', loop_index, 'duration:', dur);
return dur;

// Extract image prompt from AI response
let text = input;
if (typeof text === 'object') text = text.text || text.content || JSON.stringify(text);
text = String(text).trim();
text = text.replace(/<think[^>]*>[\s\S]*?<\/think>/gi, '').trim();
text = text.replace(/^```[\s\S]*?```$/gm, '').trim();
text = text.replace(/^Image prompt:\s*/i, '').trim();
console.log('[extract-image-prompt] Prompt:', text.substring(0, 100));
return text || 'cinematic music video scene, vibrant colors';

// Get first character image as style reference
let charImgs = workflow_context['characterImages'] || {};
let ref = charImgs['char_0'] || null;
console.log('[get-char-reference] Has reference:', !!ref);
return ref;

// Extract video prompt from AI response
let text = input;
if (typeof text === 'object') text = text.text || text.content || JSON.stringify(text);
text = String(text).trim();
text = text.replace(/<think[^>]*>[\s\S]*?<\/think>/gi, '').trim();
text = text.replace(/^```[\s\S]*?```$/gm, '').trim();
text = text.replace(/^Video prompt:\s*/i, '').trim();
console.log('[extract-video-prompt] Prompt:', text.substring(0, 100));
return text || 'Cinematic shot of a music video scene, camera slowly pans across the frame, soft lighting creates atmosphere.';

// Store scene data: image, video prompt, duration
let image = input;
let videoPrompt = input2;
let duration = input3 || 10;
let imagePrompt = input4 || '';
console.log('[store-scene-data] Scene', loop_index, '- duration:', duration);
if (!workflow_context['sceneData']) workflow_context['sceneData'] = [];
workflow_context['sceneData'].push({ image: image, videoPrompt: videoPrompt, duration: duration, imagePrompt: imagePrompt });
return { image: image, videoPrompt: videoPrompt, duration: duration };

// Extract scene data array for video loop
let data = workflow_context['sceneData'] || [];
console.log('[extract-scene-data] Got', data.length, 'scenes for video generation');
return data;

// Get image from scene data
let data = input;
if (typeof data === 'string') try { data = JSON.parse(data); } catch(e) {}
data = data || {};
console.log('[get-video-image] Scene', loop_index);
return data.image || null;

// Get video prompt from scene data
let data = input;
if (typeof data === 'string') try { data = JSON.parse(data); } catch(e) {}
data = data || {};
console.log('[get-video-prompt] Scene', loop_index);
return data.videoPrompt || 'cinematic music video scene';

// Get duration from scene data
let data = input;
if (typeof data === 'string') try { data = JSON.parse(data); } catch(e) {}
data = data || {};
let dur = data.duration || 10;
console.log('[get-video-duration] Scene', loop_index, 'duration:', dur);
return dur;

// Calculate frame count from duration (25 fps)
let duration = parseFloat(input) || 10;
let frames = Math.round(duration * 25);
// Ensure minimum 25 frames (1 second) and reasonable max
frames = Math.max(25, Math.min(frames, 375)); // 1-15 seconds
console.log('[calc-video-frames] Scene', loop_index, ':', duration, 's =', frames, 'frames');
return frames;

// Store generated video with duration
let video = input;
let duration = input2 || 10;
console.log('[store-video] Video', loop_index, 'duration:', duration);
if (!workflow_context['sceneVideos']) workflow_context['sceneVideos'] = [];
if (!workflow_context['sceneDurations']) workflow_context['sceneDurations'] = [];
workflow_context['sceneVideos'].push(video);
workflow_context['sceneDurations'].push(duration);
return video;

// Get collected scene durations
let durations = workflow_context['sceneDurations'] || [];
console.log('[get-scene-durations] Durations:', durations);
return durations;

// Get the generated music path
let musicPath = workflow_context['musicPath'];
console.log('[get-music-path] Music path:', musicPath);
return musicPath;
